import { BoardEntity } from '../../../board-entity';
import { updateDivineShield } from '../../../keywords/divine-shield';
import { CardIds } from '../../../services/card-ids';
import { pickRandom } from '../../../services/utils';
import { OnAttackInput } from '../../../simulation/on-attack';
import { RallyCard } from '../../card.interface';
import { cardMappings } from '../_card-mappings';

export const TimewarpedGuard: RallyCard = {
	cardIds: [CardIds.TimewarpedGuard_BG34_Giant_068, CardIds.TimewarpedGuard_BG34_Giant_068_G],
	rally: (minion: BoardEntity, input: OnAttackInput) => {
		const mult = minion.cardId === CardIds.TimewarpedGuard_BG34_Giant_068_G ? 2 : 1;
		// For when the Rally is triggered by another minion, eg Stoneshell Sentinel
		// 33.6.2 https://replays.firestoneapp.com/?reviewId=68d6082e-f592-4028-b191-9268e3e6d08f&turn=31&action=2
		const cardIds = cardMappings[input.attacker.cardId]?.cardIds ?? TimewarpedGuard.cardIds;
		for (let i = 0; i < mult; i++) {
			const possibleTargets = input.attackingBoard.filter((e) => !cardIds.includes(e.cardId) && !e.divineShield);
			if (possibleTargets.length > 0) {
				const target = pickRandom(possibleTargets);
				if (target != null) {
					updateDivineShield(
						target,
						input.attackingBoard,
						input.attackingHero,
						input.defendingHero,
						true,
						input.gameState,
					);
				}
			}
		}
		return { dmgDoneByAttacker: 0, dmgDoneByDefender: 0 };
	},
};
